CREATE FUNCTION "public"."record_saved_game_attendance_on_activation"() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO '' AS $$ BEGIN IF NEW.status = 'active'::public.reservation_status AND NEW.surface = 'top'::public.table_surface THEN INSERT INTO public.saved_game_attendances (saved_game_id, play_reservation_id, attended_on) SELECT saved.id, NEW.id, NEW.date FROM public.saved_games AS saved WHERE saved.table_id = NEW.table_id AND saved.user_id = NEW.user_id AND saved.status = 'active' AND NEW.date BETWEEN saved.start_date AND saved.end_date ON CONFLICT (play_reservation_id) DO NOTHING; END IF; RETURN NEW; END; $$;
